// HasProcessDefinition applies the HasEdge predicate on the "process_definition" edge.
func HasProcessDefinition() predicate.ProcessBinding {
	return predicate.ProcessBinding(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ProcessDefinitionTable, ProcessDefinitionColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasProcessDefinitionWith applies the HasEdge predicate on the "process_definition" edge with a given conditions (other predicates).
func HasProcessDefinitionWith(preds ...predicate.ProcessDefinition) predicate.ProcessBinding {
	return predicate.ProcessBinding(func(s *sql.Selector) {
		step := newProcessDefinitionStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ProcessBinding) predicate.ProcessBinding {
	return predicate.ProcessBinding(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ProcessBinding) predicate.ProcessBinding {
	return predicate.ProcessBinding(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ProcessBinding) predicate.ProcessBinding {
	return predicate.ProcessBinding(sql.NotPredicates(p))
}
